List<String> words = List.of("apple", "banana", "avocado", "blueberry", "cherry");

// groupingBy + counting()
Map<Character, Long> countByInitial = words.stream()
    .collect(Collectors.groupingBy(
        s -> s.charAt(0),
        Collectors.counting()));
// {a=2, b=2, c=1}

// toMap() でキー衝突 → 例外
// words.stream().collect(Collectors.toMap(
//     s -> s.charAt(0), s -> s)); // IllegalStateException

// toMap() でマージ関数を指定
Map<Character, String> merged = words.stream()
    .collect(Collectors.toMap(
        s -> s.charAt(0), s -> s,
        (s1, s2) -> s1 + "," + s2));
// {a=apple,avocado, b=banana,blueberry, c=cherry}

// flatMapでネストされたリストを平坦化
List<List<Integer>> nested = List.of(
    List.of(1, 2), List.of(3, 4), List.of(5));
List<Integer> flat = nested.stream()
    .flatMap(Collection::stream)
    .collect(Collectors.toList());
// [1, 2, 3, 4, 5]

// Optional.flatMapの使い方
Optional<String> name = Optional.of("Java");
Optional<String> result = name
    .map(String::toUpperCase)              // Optional<String>
    .flatMap(s -> s.equals("JAVA")
        ? Optional.of(s) : Optional.empty()); // Optional<String>
System.out.println(result); // Optional[JAVA]

