// Containerクラスの定義
abstract class Container<T> {
    abstract T getValue();
    abstract void setValue(T value);
}

// StringContainerクラスの定義
class StringContainer extends Container<String> {
    private String value;
    @Override
    // getValueメソッドの定義
    String getValue() { return value; }
    @Override
    // setValueメソッドの定義
    void setValue(String value) { this.value = value; }
}

// GenericPairクラスの定義
class GenericPair<A, B> extends Container<A> {
    private A first;
    private B second;
    @Override
    A getValue() { return first; }
    @Override
    void setValue(A value) { this.first = value; }
    B getSecond() { return second; }
}

